 84→	async create({ data }: { data: IUserCreate }): Promise<IUserBase> {
 85→		try {
 86→			const dto = plainToInstance(UserBaseDto, data);
 87→			const errors = await validate(dto, { skipMissingProperties: true });
 88→			if (errors.length > 0) {
 89→				this.logger.error(
 90→					`Validation failed for user data: ${this.formatValidationErrors({ errors })}`,
 91→				);
 92→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
 93→			}
 94→
 95→			const _id = randomUUID();
 96→			const [created] = await this.knexWrite<IUserBase>(this.tableName)
 97→				.insert({
 98→					_id,
 99→					...data,
100→					created_at: this.knexWrite.fn.now(),
101→					updated_at: this.knexWrite.fn.now(),
102→				})
103→				.returning('*');
104→
105→			if (!created) {
106→				throw new Error('Failed to create user');
107→			}
108→
109→			this.logger.debug(`Created user with id ${_id}`);
110→			return created;
111→		} catch (error) {
112→			this.logger.error(`Failed to create user: ${(error as Error).message}`);
113→			throw error;
114→		}
115→	}
