export interface IOAuthAccountBase {
	_id: string;
	user_id: string;
	provider: 'github' | 'google';
	provider_id: string;
	email: string | null;
	access_token: string | null;
	created_at: Date;
	updated_at: Date;
	deleted_at: Date | null;
}

import type { IOAuthAccountBase } from '@modules/oauth-account/types/oauth-account.base.interface';

export type IOAuthAccountCreate = Omit<
	IOAuthAccountBase,
	'_id' | 'created_at' | 'updated_at' | 'deleted_at'
>;

import {
	IsDate,
	IsEmail,
	IsIn,
	IsNotEmpty,
	IsOptional,
	IsString,
	IsUUID,
} from 'class-validator';

export class OAuthAccountBaseDto {
	@IsUUID()
	@IsNotEmpty()
	_id: string;

	@IsUUID()
	@IsNotEmpty()
	user_id: string;

	@IsIn(['github', 'google'])
	@IsNotEmpty()
	provider: 'github' | 'google';

	@IsString()
	@IsNotEmpty()
	provider_id: string;

	@IsOptional()
	@IsEmail()
	email: string | null;

	@IsOptional()
	@IsString()
	access_token: string | null;

	@IsDate()
	@IsNotEmpty()
	created_at: Date;

	@IsDate()
	@IsNotEmpty()
	updated_at: Date;

	@IsOptional()
	@IsDate()
	deleted_at: Date | null;
}

import { OmitType } from '@nestjs/swagger';

import { OAuthAccountBaseDto } from '@modules/oauth-account/dto/oauth-account.base.dto';

export class OAuthAccountCreateDto extends OmitType(OAuthAccountBaseDto, [
	'_id',
	'created_at',
	'updated_at',
	'deleted_at',
] as const) {}

import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { OAuthAccountBaseDto } from '@modules/oauth-account/dto/oauth-account.base.dto';
import { IOAuthAccountBase } from '@modules/oauth-account/types/oauth-account.base.interface';
import { IOAuthAccountCreate } from '@modules/oauth-account/types/oauth-account.create.interface';

import { TABLE_NAME_OAUTH_ACCOUNTS } from '@constants/db.constant';
import { ENCRYPTION_KEY } from '@constants/env-variables.constant';
import { decrypt, encrypt } from '@utils/encryption.util';
import { getEnv } from '@utils/get-env-variable.util';

@Injectable()
export class OAuthAccountModel {
	private readonly logger = new Logger(OAuthAccountModel.name);
	private readonly tableName = TABLE_NAME_OAUTH_ACCOUNTS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	private getEncryptionKey(): string {
		return getEnv<string>({ key: ENCRYPTION_KEY });
	}

	private decryptToken({ row }: { row: IOAuthAccountBase }): IOAuthAccountBase {
		if (row.access_token === null) {
			return row;
		}
		const key = this.getEncryptionKey();
		return { ...row, access_token: decrypt({ ciphertext: row.access_token, key }) };
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}

	async findByProviderAndProviderId({
		provider,
		providerId,
	}: {
		provider: IOAuthAccountBase['provider'];
		providerId: IOAuthAccountBase['provider_id'];
	}): Promise<IOAuthAccountBase | null> {
		try {
			const result = await this.knexRead<IOAuthAccountBase>(this.tableName)
				.where({ provider, provider_id: providerId })
				.whereNull('deleted_at')
				.first();

			if (!result) {
				return null;
			}

			const dto = plainToInstance(OAuthAccountBaseDto, result);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for oauth account data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(
					`Validation failed: ${this.formatValidationErrors({ errors })}`,
				);
			}

			return this.decryptToken({ row: result });
		} catch (error) {
			this.logger.error(
				`Failed to find oauth account by provider ${provider} and providerId ${providerId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findByUserId({
		userId,
	}: {
		userId: IOAuthAccountBase['user_id'];
	}): Promise<IOAuthAccountBase[]> {
		try {
			const results = await this.knexRead<IOAuthAccountBase>(this.tableName)
				.where({ user_id: userId })
				.whereNull('deleted_at');

			return results.map((row) => this.decryptToken({ row }));
		} catch (error) {
			this.logger.error(
				`Failed to find oauth accounts for user ${userId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findByEmail({
		email,
	}: {
		email: IOAuthAccountBase['email'];
	}): Promise<IOAuthAccountBase[]> {
		try {
			const results = await this.knexRead<IOAuthAccountBase>(this.tableName)
				.where({ email })
				.whereNull('deleted_at');

			return results.map((row) => this.decryptToken({ row }));
		} catch (error) {
			this.logger.error(
				`Failed to find oauth accounts by email ${email}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async create({ data }: { data: IOAuthAccountCreate }): Promise<IOAuthAccountBase> {
		try {
			const dto = plainToInstance(OAuthAccountBaseDto, data);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for oauth account data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(
					`Validation failed: ${this.formatValidationErrors({ errors })}`,
				);
			}

			const key = this.getEncryptionKey();
			const encryptedToken =
				data.access_token !== null && data.access_token !== undefined
					? encrypt({ plaintext: data.access_token, key })
					: null;

			const _id = randomUUID();
			const [created] = await this.knexWrite<IOAuthAccountBase>(this.tableName)
				.insert({
					_id,
					...data,
					access_token: encryptedToken,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create oauth account');
			}

			this.logger.debug(`Created oauth account with id ${_id}`);
			return this.decryptToken({ row: created });
		} catch (error) {
			this.logger.error(`Failed to create oauth account: ${(error as Error).message}`);
			throw error;
		}
	}

	async updateAccessToken({
		oauthAccountId,
		accessToken,
	}: {
		oauthAccountId: IOAuthAccountBase['_id'];
		accessToken: string | null;
	}): Promise<void> {
		try {
			const key = this.getEncryptionKey();
			const encryptedToken =
				accessToken !== null
					? encrypt({ plaintext: accessToken, key })
					: null;

			await this.knexWrite<IOAuthAccountBase>(this.tableName)
				.where({ _id: oauthAccountId })
				.whereNull('deleted_at')
				.update({
					access_token: encryptedToken,
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Updated access token for oauth account ${oauthAccountId}`);
		} catch (error) {
			this.logger.error(
				`Failed to update access token for oauth account ${oauthAccountId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}

