		const module: TestingModule = await Test.createTestingModule({
			providers: [
				OAuthAccountService,
				{ provide: OAuthAccountModel, useValue: mockOAuthAccountModel },
			],
		}).compile();

		service = module.get<OAuthAccountService>(OAuthAccountService);

		jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		jest.spyOn(Logger.prototype, 'debug').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(service).toBeDefined();
	});

	describe('findByProviderAndProviderId', () => {
		it('should delegate to model and return result', async () => {
			mockOAuthAccountModel.findByProviderAndProviderId.mockResolvedValue(
				mockOAuthAccount,
			);

			const result = await service.findByProviderAndProviderId({
				provider: 'github',
				providerId: 'gh_12345',
			});

			expect(
				mockOAuthAccountModel.findByProviderAndProviderId,
			).toHaveBeenCalledWith({ provider: 'github', providerId: 'gh_12345' });
			expect(result).toEqual(mockOAuthAccount);
		});

		it('should return null when not found', async () => {
			mockOAuthAccountModel.findByProviderAndProviderId.mockResolvedValue(null);

			const result = await service.findByProviderAndProviderId({
				provider: 'github',
				providerId: 'non-existent',
			});

			expect(result).toBeNull();
		});
	});

	describe('findByUserId', () => {
		it('should delegate to model and return results', async () => {
			mockOAuthAccountModel.findByUserId.mockResolvedValue([mockOAuthAccount]);

			const result = await service.findByUserId({
				userId: mockOAuthAccount.user_id,
			});

			expect(mockOAuthAccountModel.findByUserId).toHaveBeenCalledWith({
				userId: mockOAuthAccount.user_id,
			});
			expect(result).toEqual([mockOAuthAccount]);
		});

		it('should return empty array when no accounts found', async () => {
			mockOAuthAccountModel.findByUserId.mockResolvedValue([]);

			const result = await service.findByUserId({ userId: 'non-existent' });

			expect(result).toEqual([]);
		});
	});

	describe('findByEmail', () => {
		it('should delegate to model and return results', async () => {
			mockOAuthAccountModel.findByEmail.mockResolvedValue([mockOAuthAccount]);

			const result = await service.findByEmail({ email: 'test@example.com' });

			expect(mockOAuthAccountModel.findByEmail).toHaveBeenCalledWith({
				email: 'test@example.com',
			});
			expect(result).toEqual([mockOAuthAccount]);
		});

		it('should return empty array when no accounts found', async () => {
			mockOAuthAccountModel.findByEmail.mockResolvedValue([]);

			const result = await service.findByEmail({ email: 'notfound@example.com' });

			expect(result).toEqual([]);
		});
	});

	describe('create', () => {
		const createData: IOAuthAccountCreate = {
			user_id: '660e8400-e29b-41d4-a716-446655440001',
			provider: 'github',
			provider_id: 'gh_12345',
			email: 'test@example.com',
			access_token: 'plain-token',
		};

		it('should delegate to model and return created account', async () => {
			mockOAuthAccountModel.create.mockResolvedValue(mockOAuthAccount);

			const result = await service.create({ data: createData });

			expect(mockOAuthAccountModel.create).toHaveBeenCalledWith({ data: createData });
			expect(result).toEqual(mockOAuthAccount);
		});
	});

	describe('updateAccessToken', () => {
		it('should delegate to model', async () => {
			mockOAuthAccountModel.updateAccessToken.mockResolvedValue(undefined);

			await service.updateAccessToken({
				oauthAccountId: mockOAuthAccount._id,
				accessToken: 'new-token',
			});

			expect(mockOAuthAccountModel.updateAccessToken).toHaveBeenCalledWith({
				oauthAccountId: mockOAuthAccount._id,
				accessToken: 'new-token',
			});
		});

		it('should delegate null access token to model', async () => {
			mockOAuthAccountModel.updateAccessToken.mockResolvedValue(undefined);

			await service.updateAccessToken({
				oauthAccountId: mockOAuthAccount._id,
				accessToken: null,
			});

			expect(mockOAuthAccountModel.updateAccessToken).toHaveBeenCalledWith({
				oauthAccountId: mockOAuthAccount._id,
				accessToken: null,
			});
		});
	});
});
